package com.ecommerce.search.service;

import org.springframework.stereotype.Component;

import java.util.Set;
import java.util.regex.Pattern;

@Component
public class InputSanitizer {

    // Allowlist of characters for search queries
    private static final Pattern SAFE_QUERY_PATTERN = Pattern.compile("[^a-zA-Z0-9\\s\\-_.,&'+()\"]+");
    private static final Pattern MULTIPLE_SPACES = Pattern.compile("\\s{2,}");
    private static final int MAX_QUERY_LENGTH = 500;

    // Allowlist of valid sort fields
    private static final Set<String> ALLOWED_SORT_FIELDS = Set.of(
            "price", "averageRating", "reviewCount", "createdAt", "name", "relevance"
    );

    // Allowlist of valid attribute keys
    private static final Pattern SAFE_ATTRIBUTE_KEY = Pattern.compile("^[a-zA-Z0-9_-]{1,50}$");
    private static final Pattern SAFE_ATTRIBUTE_VALUE = Pattern.compile("^[a-zA-Z0-9\\s_.,&'-]{1,200}$");

    public String sanitizeSearchQuery(String input) {
        if (input == null || input.isBlank()) {
            return "";
        }
        String sanitized = input.trim();
        if (sanitized.length() > MAX_QUERY_LENGTH) {
            sanitized = sanitized.substring(0, MAX_QUERY_LENGTH);
        }
        // Remove potentially dangerous characters
        sanitized = SAFE_QUERY_PATTERN.matcher(sanitized).replaceAll("");
        sanitized = MULTIPLE_SPACES.matcher(sanitized).replaceAll(" ");
        return sanitized.trim();
    }

    public String sanitizeId(String id) {
        if (id == null || id.isBlank()) {
            return null;
        }
        String sanitized = id.trim();
        if (!sanitized.matches("^[a-zA-Z0-9_-]{1,64}$")) {
            throw new IllegalArgumentException("Invalid ID format");
        }
        return sanitized;
    }

    public boolean isValidSortField(String field) {
        return field == null || ALLOWED_SORT_FIELDS.contains(field);
    }

    public boolean isValidAttributeKey(String key) {
        return key != null && SAFE_ATTRIBUTE_KEY.matcher(key).matches();
    }

    public boolean isValidAttributeValue(String value) {
        return value != null && SAFE_ATTRIBUTE_VALUE.matcher(value).matches();
    }

    public String sanitizeForLog(String input) {
        if (input == null) return "null";
        // Remove newlines and control characters to prevent log injection
        return input.replaceAll("[\\r\\n\\t]", " ")
                .replaceAll("[^\\x20-\\x7E]", "")
                .substring(0, Math.min(input.length(), 200));
    }
}

