package com.ecommerce.search.service;

import org.elasticsearch.action.admin.indices.delete.DeleteIndexRequest;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.client.indices.CreateIndexRequest;
import org.elasticsearch.client.indices.CreateIndexResponse;
import org.elasticsearch.client.indices.GetIndexRequest;
import org.elasticsearch.common.settings.Settings;
import org.elasticsearch.common.xcontent.XContentBuilder;
import org.elasticsearch.common.xcontent.XContentFactory;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;

import javax.annotation.PostConstruct;
import java.io.IOException;

@Service
public class ElasticsearchIndexService {

    private static final Logger logger = LoggerFactory.getLogger(ElasticsearchIndexService.class);

    public static final String PRODUCTS_INDEX = "products";
    public static final String SEARCH_QUERIES_INDEX = "search_queries";

    private final RestHighLevelClient client;

    @Autowired
    public ElasticsearchIndexService(RestHighLevelClient client) {
        this.client = client;
    }

    @PostConstruct
    public void initializeIndices() {
        try {
            createProductsIndexIfNotExists();
            createSearchQueriesIndexIfNotExists();
            logger.info("Elasticsearch indices initialized successfully");
        } catch (IOException e) {
            logger.error("Failed to initialize Elasticsearch indices", e);
            throw new RuntimeException("Cannot initialize search indices", e);
        }
    }

    private void createProductsIndexIfNotExists() throws IOException {
        GetIndexRequest getRequest = new GetIndexRequest(PRODUCTS_INDEX);
        if (client.indices().exists(getRequest, RequestOptions.DEFAULT)) {
            logger.info("Products index already exists");
            return;
        }

        CreateIndexRequest request = new CreateIndexRequest(PRODUCTS_INDEX);

        request.settings(Settings.builder()
                .put("index.number_of_shards", 3)
                .put("index.number_of_replicas", 1)
                .put("index.max_result_window", 10000)
                .put("analysis.analyzer.product_analyzer.type", "custom")
                .put("analysis.analyzer.product_analyzer.tokenizer", "standard")
                .putList("analysis.analyzer.product_analyzer.filter",
                        "lowercase", "asciifolding", "porter_stem")
                .put("analysis.analyzer.autocomplete_analyzer.type", "custom")
                .put("analysis.analyzer.autocomplete_analyzer.tokenizer", "autocomplete_tokenizer")
                .put("analysis.tokenizer.autocomplete_tokenizer.type", "edge_ngram")
                .put("analysis.tokenizer.autocomplete_tokenizer.min_gram", 2)
                .put("analysis.tokenizer.autocomplete_tokenizer.max_gram", 20)
                .putList("analysis.tokenizer.autocomplete_tokenizer.token_chars", "letter", "digit")
        );

        XContentBuilder mapping = XContentFactory.jsonBuilder();
        mapping.startObject();
        {
            mapping.startObject("properties");
            {
                mapping.startObject("name");
                mapping.field("type", "text");
                mapping.field("analyzer", "product_analyzer");
                mapping.startObject("fields");
                {
                    mapping.startObject("keyword");
                    mapping.field("type", "keyword");
                    mapping.field("ignore_above", 500);
                    mapping.endObject();
                    mapping.startObject("autocomplete");
                    mapping.field("type", "text");
                    mapping.field("analyzer", "autocomplete_analyzer");
                    mapping.field("search_analyzer", "standard");
                    mapping.endObject();
                }
                mapping.endObject();
                mapping.endObject();

                mapping.startObject("description");
                mapping.field("type", "text");
                mapping.field("analyzer", "product_analyzer");
                mapping.endObject();

                mapping.startObject("price");
                mapping.field("type", "scaled_float");
                mapping.field("scaling_factor", 100);
                mapping.endObject();

                mapping.startObject("category");
                mapping.field("type", "keyword");
                mapping.endObject();

                mapping.startObject("brand");
                mapping.field("type", "keyword");
                mapping.endObject();

                mapping.startObject("tags");
                mapping.field("type", "keyword");
                mapping.endObject();

                mapping.startObject("attributes");
                mapping.field("type", "object");
                mapping.field("enabled", true);
                mapping.endObject();

                mapping.startObject("stockQuantity");
                mapping.field("type", "integer");
                mapping.endObject();

                mapping.startObject("averageRating");
                mapping.field("type", "float");
                mapping.endObject();

                mapping.startObject("reviewCount");
                mapping.field("type", "integer");
                mapping.endObject();

                mapping.startObject("createdAt");
                mapping.field("type", "date");
                mapping.endObject();

                mapping.startObject("updatedAt");
                mapping.field("type", "date");
                mapping.endObject();

                mapping.startObject("active");
                mapping.field("type", "boolean");
                mapping.endObject();

                mapping.startObject("suggest");
                mapping.field("type", "completion");
                mapping.endObject();
            }
            mapping.endObject();
        }
        mapping.endObject();

        request.mapping(mapping);

        CreateIndexResponse response = client.indices().create(request, RequestOptions.DEFAULT);
        logger.info("Products index created: acknowledged={}", response.isAcknowledged());
    }

    private void createSearchQueriesIndexIfNotExists() throws IOException {
        GetIndexRequest getRequest = new GetIndexRequest(SEARCH_QUERIES_INDEX);
        if (client.indices().exists(getRequest, RequestOptions.DEFAULT)) {
            logger.info("Search queries index already exists");
            return;
        }

        CreateIndexRequest request = new CreateIndexRequest(SEARCH_QUERIES_INDEX);

        request.settings(Settings.builder()
                .put("index.number_of_shards", 2)
                .put("index.number_of_replicas", 1)
        );

        XContentBuilder mapping = XContentFactory.jsonBuilder();
        mapping.startObject();
        {
            mapping.startObject("properties");
            {
                mapping.startObject("queryText");
                mapping.field("type", "text");
                mapping.startObject("fields");
                mapping.startObject("keyword");
                mapping.field("type", "keyword");
                mapping.field("ignore_above", 500);
                mapping.endObject();
                mapping.endObject();
                mapping.endObject();

                mapping.startObject("userId");
                mapping.field("type", "keyword");
                mapping.endObject();

                mapping.startObject("resultCount");
                mapping.field("type", "long");
                mapping.endObject();

                mapping.startObject("timeTookMs");
                mapping.field("type", "long");
                mapping.endObject();

                mapping.startObject("timestamp");
                mapping.field("type", "date");
                mapping.endObject();

                mapping.startObject("sessionId");
                mapping.field("type", "keyword");
                mapping.endObject();

                mapping.startObject("filters");
                mapping.field("type", "text");
                mapping.endObject();
            }
            mapping.endObject();
        }
        mapping.endObject();

        request.mapping(mapping);

        CreateIndexResponse response = client.indices().create(request, RequestOptions.DEFAULT);
        logger.info("Search queries index created: acknowledged={}", response.isAcknowledged());
    }
}

