package com.ecommerce.search.service;

import com.ecommerce.search.model.Product;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.datatype.jsr310.JavaTimeModule;
import org.elasticsearch.action.bulk.BulkRequest;
import org.elasticsearch.action.bulk.BulkResponse;
import org.elasticsearch.action.delete.DeleteRequest;
import org.elasticsearch.action.delete.DeleteResponse;
import org.elasticsearch.action.get.GetRequest;
import org.elasticsearch.action.get.GetResponse;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.index.IndexResponse;
import org.elasticsearch.action.update.UpdateRequest;
import org.elasticsearch.action.update.UpdateResponse;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.common.xcontent.XContentType;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.time.Instant;
import java.util.*;

@Service
public class ProductIndexingService {

    private static final Logger logger = LoggerFactory.getLogger(ProductIndexingService.class);

    private final RestHighLevelClient client;
    private final InputSanitizer sanitizer;
    private final ObjectMapper objectMapper;

    @Autowired
    public ProductIndexingService(RestHighLevelClient client, InputSanitizer sanitizer) {
        this.client = client;
        this.sanitizer = sanitizer;
        this.objectMapper = new ObjectMapper();
        this.objectMapper.registerModule(new JavaTimeModule());
    }

    public String indexProduct(Product product) throws IOException {
        validateProduct(product);

        if (product.getId() == null || product.getId().isBlank()) {
            product.setId(UUID.randomUUID().toString());
        }

        product.setCreatedAt(Instant.now());
        product.setUpdatedAt(Instant.now());

        Map<String, Object> productMap = buildProductMap(product);

        IndexRequest request = new IndexRequest(ElasticsearchIndexService.PRODUCTS_INDEX)
                .id(product.getId())
                .source(productMap, XContentType.JSON);

        IndexResponse response = client.index(request, RequestOptions.DEFAULT);
        logger.info("Product indexed: id={}, result={}", sanitizer.sanitizeForLog(product.getId()), response.getResult());
        return product.getId();
    }

    public void bulkIndexProducts(List<Product> products) throws IOException {
        if (products == null || products.isEmpty()) {
            return;
        }

        if (products.size() > 1000) {
            throw new IllegalArgumentException("Bulk index limit is 1000 products per request");
        }

        BulkRequest bulkRequest = new BulkRequest();

        for (Product product : products) {
            validateProduct(product);
            if (product.getId() == null || product.getId().isBlank()) {
                product.setId(UUID.randomUUID().toString());
            }
            product.setCreatedAt(Instant.now());
            product.setUpdatedAt(Instant.now());

            Map<String, Object> productMap = buildProductMap(product);

            bulkRequest.add(new IndexRequest(ElasticsearchIndexService.PRODUCTS_INDEX)
                    .id(product.getId())
                    .source(productMap, XContentType.JSON));
        }

        BulkResponse response = client.bulk(bulkRequest, RequestOptions.DEFAULT);
        if (response.hasFailures()) {
            logger.error("Bulk indexing had failures: {}", response.buildFailureMessage());
            throw new IOException("Bulk indexing partially failed: " + response.buildFailureMessage());
        }
        logger.info("Bulk indexed {} products successfully", products.size());
    }

    public Product getProduct(String id) throws IOException {
        String sanitizedId = sanitizer.sanitizeId(id);
        GetRequest request = new GetRequest(ElasticsearchIndexService.PRODUCTS_INDEX, sanitizedId);
        GetResponse response = client.get(request, RequestOptions.DEFAULT);

        if (!response.isExists()) {
            return null;
        }

        return objectMapper.convertValue(response.getSourceAsMap(), Product.class);
    }

    public String updateProduct(String id, Product product) throws IOException {
        String sanitizedId = sanitizer.sanitizeId(id);
        validateProduct(product);

        product.setUpdatedAt(Instant.now());
        Map<String, Object> productMap = buildProductMap(product);

        UpdateRequest request = new UpdateRequest(ElasticsearchIndexService.PRODUCTS_INDEX, sanitizedId)
                .doc(productMap, XContentType.JSON);

        UpdateResponse response = client.update(request, RequestOptions.DEFAULT);
        logger.info("Product updated: id={}, result={}", sanitizer.sanitizeForLog(sanitizedId), response.getResult());
        return sanitizedId;
    }

    public boolean deleteProduct(String id) throws IOException {
        String sanitizedId = sanitizer.sanitizeId(id);
        DeleteRequest request = new DeleteRequest(ElasticsearchIndexService.PRODUCTS_INDEX, sanitizedId);
        DeleteResponse response = client.delete(request, RequestOptions.DEFAULT);
        logger.info("Product deleted: id={}, result={}", sanitizer.sanitizeForLog(sanitizedId), response.getResult());
        return response.getResult().name().equals("DELETED");
    }

    private void validateProduct(Product product) {
        if (product == null) {
            throw new IllegalArgumentException("Product cannot be null");
        }
        if (product.getName() == null || product.getName().isBlank()) {
            throw new IllegalArgumentException("Product name is required");
        }
        if (product.getPrice() == null || product.getPrice().signum() < 0) {
            throw new IllegalArgumentException("Product price must be non-negative");
        }
        if (product.getCategory() == null || product.getCategory().isBlank()) {
            throw new IllegalArgumentException("Product category is required");
        }

        // Validate attributes if present
        if (product.getAttributes() != null) {
            for (Map.Entry<String, String> entry : product.getAttributes().entrySet()) {
                if (!sanitizer.isValidAttributeKey(entry.getKey())) {
                    throw new IllegalArgumentException("Invalid attribute key: " + sanitizer.sanitizeForLog(entry.getKey()));
                }
                if (!sanitizer.isValidAttributeValue(entry.getValue())) {
                    throw new IllegalArgumentException("Invalid attribute value for key: " + sanitizer.sanitizeForLog(entry.getKey()));
                }
            }
        }
    }

    private Map<String, Object> buildProductMap(Product product) {
        Map<String, Object> map = new HashMap<>();
        map.put("name", product.getName());
        map.put("description", product.getDescription());
        map.put("price", product.getPrice());
        map.put("category", product.getCategory());
        map.put("brand", product.getBrand());
        map.put("tags", product.getTags());
        map.put("attributes", product.getAttributes());
        map.put("stockQuantity", product.getStockQuantity());
        map.put("averageRating", product.getAverageRating());
        map.put("reviewCount", product.getReviewCount());
        map.put("createdAt", product.getCreatedAt() != null ? product.getCreatedAt().toString() : null);
        map.put("updatedAt", product.getUpdatedAt() != null ? product.getUpdatedAt().toString() : null);
        map.put("active", product.isActive());

        // Build suggestion input from name and brand
        Map<String, Object> suggest = new HashMap<>();
        List<String> suggestInput = new ArrayList<>();
        if (product.getName() != null) suggestInput.add(product.getName());
        if (product.getBrand() != null) suggestInput.add(product.getBrand());
        suggest.put("input", suggestInput);
        map.put("suggest", suggest);

        return map;
    }
}

