package com.ecommerce.search.service;

import com.ecommerce.search.model.Product;
import com.ecommerce.search.model.SearchQuery;
import com.ecommerce.search.model.SearchQueryLog;
import com.ecommerce.search.model.SearchResult;
import com.ecommerce.search.model.SearchResult.FacetBucket;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.datatype.jsr310.JavaTimeModule;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.search.SearchRequest;
import org.elasticsearch.action.search.SearchResponse;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.common.xcontent.XContentType;
import org.elasticsearch.index.query.BoolQueryBuilder;
import org.elasticsearch.index.query.MultiMatchQueryBuilder;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.search.SearchHit;
import org.elasticsearch.search.aggregations.AggregationBuilders;
import org.elasticsearch.search.aggregations.bucket.range.Range;
import org.elasticsearch.search.aggregations.bucket.range.RangeAggregationBuilder;
import org.elasticsearch.search.aggregations.bucket.terms.Terms;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.elasticsearch.search.sort.SortOrder;
import org.elasticsearch.search.suggest.SuggestBuilder;
import org.elasticsearch.search.suggest.SuggestBuilders;
import org.elasticsearch.search.suggest.completion.CompletionSuggestion;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.time.Instant;
import java.util.*;

@Service
public class ProductSearchService {

    private static final Logger logger = LoggerFactory.getLogger(ProductSearchService.class);

    private final RestHighLevelClient client;
    private final InputSanitizer sanitizer;
    private final ObjectMapper objectMapper;

    @Autowired
    public ProductSearchService(RestHighLevelClient client, InputSanitizer sanitizer) {
        this.client = client;
        this.sanitizer = sanitizer;
        this.objectMapper = new ObjectMapper();
        this.objectMapper.registerModule(new JavaTimeModule());
    }

    public SearchResult search(SearchQuery query, String userId, String sessionId) throws IOException {
        // Sanitize the query text
        String sanitizedQuery = sanitizer.sanitizeSearchQuery(query.getQueryText());
        if (sanitizedQuery.isEmpty()) {
            throw new IllegalArgumentException("Search query cannot be empty after sanitization");
        }

        // Validate sort field against allowlist
        if (query.getSortField() != null && !sanitizer.isValidSortField(query.getSortField())) {
            throw new IllegalArgumentException("Invalid sort field");
        }

        // Validate attribute filters
        if (query.getAttributeFilters() != null) {
            for (Map.Entry<String, String> entry : query.getAttributeFilters().entrySet()) {
                if (!sanitizer.isValidAttributeKey(entry.getKey())) {
                    throw new IllegalArgumentException("Invalid attribute filter key");
                }
                if (!sanitizer.isValidAttributeValue(entry.getValue())) {
                    throw new IllegalArgumentException("Invalid attribute filter value");
                }
            }
        }

        SearchRequest searchRequest = new SearchRequest(ElasticsearchIndexService.PRODUCTS_INDEX);
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();

        // Build the main query
        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();

        // Full-text search across name and description with boosting
        MultiMatchQueryBuilder multiMatch = QueryBuilders.multiMatchQuery(sanitizedQuery,
                        "name^3", "name.autocomplete^2", "description", "brand^2", "tags^1.5")
                .type(MultiMatchQueryBuilder.Type.BEST_FIELDS)
                .fuzziness("AUTO")
                .minimumShouldMatch("75%");

        boolQuery.must(multiMatch);

        // Only return active products
        boolQuery.filter(QueryBuilders.termQuery("active", true));

        // Apply category filter
        if (query.getCategoryFilter() != null && !query.getCategoryFilter().isBlank()) {
            boolQuery.filter(QueryBuilders.termQuery("category", query.getCategoryFilter()));
        }

        // Apply brand filter
        if (query.getBrandFilter() != null && !query.getBrandFilter().isBlank()) {
            boolQuery.filter(QueryBuilders.termQuery("brand", query.getBrandFilter()));
        }

        // Apply price range filter
        if (query.getMinPrice() != null || query.getMaxPrice() != null) {
            var rangeQuery = QueryBuilders.rangeQuery("price");
            if (query.getMinPrice() != null) {
                rangeQuery.gte(query.getMinPrice());
            }
            if (query.getMaxPrice() != null) {
                rangeQuery.lte(query.getMaxPrice());
            }
            boolQuery.filter(rangeQuery);
        }

        // Apply rating filter
        if (query.getMinRating() != null) {
            boolQuery.filter(QueryBuilders.rangeQuery("averageRating").gte(query.getMinRating()));
        }

        // Apply tag filters
        if (query.getTagFilters() != null && !query.getTagFilters().isEmpty()) {
            for (String tag : query.getTagFilters()) {
                boolQuery.filter(QueryBuilders.termQuery("tags", tag));
            }
        }

        // Apply attribute filters
        if (query.getAttributeFilters() != null) {
            for (Map.Entry<String, String> entry : query.getAttributeFilters().entrySet()) {
                boolQuery.filter(QueryBuilders.termQuery("attributes." + entry.getKey() + ".keyword", entry.getValue()));
            }
        }

        sourceBuilder.query(boolQuery);

        // Pagination
        sourceBuilder.from(query.getPage() * query.getSize());
        sourceBuilder.size(query.getSize());

        // Sorting
        if (query.getSortField() != null && !query.getSortField().equals("relevance")) {
            String sortField = query.getSortField();
            if ("name".equals(sortField)) {
                sortField = "name.keyword";
            }
            SortOrder order = "desc".equalsIgnoreCase(query.getSortOrder()) ? SortOrder.DESC : SortOrder.ASC;
            sourceBuilder.sort(sortField, order);
        }

        // Faceted navigation (aggregations)
        if (query.isIncludeFacets()) {
            sourceBuilder.aggregation(AggregationBuilders.terms("categories")
                    .field("category")
                    .size(50));

            sourceBuilder.aggregation(AggregationBuilders.terms("brands")
                    .field("brand")
                    .size(50));

            sourceBuilder.aggregation(AggregationBuilders.terms("tags_agg")
                    .field("tags")
                    .size(30));

            RangeAggregationBuilder priceRanges = AggregationBuilders.range("price_ranges")
                    .field("price")
                    .addUnboundedTo("Under $25", 25)
                    .addRange("$25 - $50", 25, 50)
                    .addRange("$50 - $100", 50, 100)
                    .addRange("$100 - $200", 100, 200)
                    .addUnboundedFrom("$200+", 200);
            sourceBuilder.aggregation(priceRanges);

            RangeAggregationBuilder ratingRanges = AggregationBuilders.range("rating_ranges")
                    .field("averageRating")
                    .addRange("4+ Stars", 4, 5.01)
                    .addRange("3+ Stars", 3, 5.01)
                    .addRange("2+ Stars", 2, 5.01)
                    .addRange("1+ Stars", 1, 5.01);
            sourceBuilder.aggregation(ratingRanges);
        }

        // Source filtering - only return needed fields
        sourceBuilder.fetchSource(new String[]{
                "name", "description", "price", "category", "brand", "tags",
                "attributes", "stockQuantity", "averageRating", "reviewCount",
                "createdAt", "active"
        }, null);

        searchRequest.source(sourceBuilder);

        // Execute search
        SearchResponse searchResponse = client.search(searchRequest, RequestOptions.DEFAULT);

        // Build result
        SearchResult result = new SearchResult();
        result.setPage(query.getPage());
        result.setSize(query.getSize());
        result.setTotalHits(searchResponse.getHits().getTotalHits().value);
        result.setTimeTookMs(searchResponse.getTook().getMillis());

        // Parse products
        List<Product> products = new ArrayList<>();
        for (SearchHit hit : searchResponse.getHits().getHits()) {
            Product product = objectMapper.convertValue(hit.getSourceAsMap(), Product.class);
            product.setId(hit.getId());
            products.add(product);
        }
        result.setProducts(products);

        // Parse facets
        if (query.isIncludeFacets() && searchResponse.getAggregations() != null) {
            Map<String, List<FacetBucket>> facets = new HashMap<>();

            Terms categories = searchResponse.getAggregations().get("categories");
            if (categories != null) {
                List<FacetBucket> categoryBuckets = new ArrayList<>();
                for (Terms.Bucket bucket : categories.getBuckets()) {
                    categoryBuckets.add(new FacetBucket(bucket.getKeyAsString(), bucket.getDocCount()));
                }
                facets.put("categories", categoryBuckets);
            }

            Terms brands = searchResponse.getAggregations().get("brands");
            if (brands != null) {
                List<FacetBucket> brandBuckets = new ArrayList<>();
                for (Terms.Bucket bucket : brands.getBuckets()) {
                    brandBuckets.add(new FacetBucket(bucket.getKeyAsString(), bucket.getDocCount()));
                }
                facets.put("brands", brandBuckets);
            }

            Terms tagsAgg = searchResponse.getAggregations().get("tags_agg");
            if (tagsAgg != null) {
                List<FacetBucket> tagBuckets = new ArrayList<>();
                for (Terms.Bucket bucket : tagsAgg.getBuckets()) {
                    tagBuckets.add(new FacetBucket(bucket.getKeyAsString(), bucket.getDocCount()));
                }
                facets.put("tags", tagBuckets);
            }

            Range priceRanges = searchResponse.getAggregations().get("price_ranges");
            if (priceRanges != null) {
                List<FacetBucket> priceBuckets = new ArrayList<>();
                for (Range.Bucket bucket : priceRanges.getBuckets()) {
                    priceBuckets.add(new FacetBucket(bucket.getKeyAsString(), bucket.getDocCount()));
                }
                facets.put("priceRanges", priceBuckets);
            }

            Range ratingRanges = searchResponse.getAggregations().get("rating_ranges");
            if (ratingRanges != null) {
                List<FacetBucket> ratingBuckets = new ArrayList<>();
                for (Range.Bucket bucket : ratingRanges.getBuckets()) {
                    ratingBuckets.add(new FacetBucket(bucket.getKeyAsString(), bucket.getDocCount()));
                }
                facets.put("ratingRanges", ratingBuckets);
            }

            result.setFacets(facets);
        }

        // Log the search query asynchronously (fire and forget, but don't log sensitive data)
        logSearchQuery(sanitizedQuery, userId, sessionId, result.getTotalHits(), result.getTimeTookMs(), query);

        return result;
    }

    public List<String> suggest(String prefix) throws IOException {
        String sanitizedPrefix = sanitizer.sanitizeSearchQuery(prefix);
        if (sanitizedPrefix.isEmpty() || sanitizedPrefix.length() < 2) {
            return Collections.emptyList();
        }

        SearchRequest searchRequest = new SearchRequest(ElasticsearchIndexService.PRODUCTS_INDEX);
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();
        sourceBuilder.size(0);

        SuggestBuilder suggestBuilder = new SuggestBuilder();
        suggestBuilder.addSuggestion("product-suggest",
                SuggestBuilders.completionSuggestion("suggest")
                        .prefix(sanitizedPrefix)
                        .size(10)
                        .skipDuplicates(true));

        sourceBuilder.suggest(suggestBuilder);
        searchRequest.source(sourceBuilder);

        SearchResponse response = client.search(searchRequest, RequestOptions.DEFAULT);

        List<String> suggestions = new ArrayList<>();
        if (response.getSuggest() != null) {
            CompletionSuggestion suggestion = response.getSuggest().getSuggestion("product-suggest");
            if (suggestion != null) {
                for (CompletionSuggestion.Entry entry : suggestion.getEntries()) {
                    for (CompletionSuggestion.Entry.Option option : entry.getOptions()) {
                        suggestions.add(option.getText().string());
                    }
                }
            }
        }

        return suggestions;
    }

    private void logSearchQuery(String queryText, String userId, String sessionId,
                                long resultCount, long timeTookMs, SearchQuery originalQuery) {
        try {
            SearchQueryLog log = new SearchQueryLog();
            log.setId(UUID.randomUUID().toString());
            // SECURE: Don't log raw user input; use sanitized version
            log.setQueryText(queryText);
            // SECURE: Hash or anonymize userId if needed for privacy
            log.setUserId(userId != null ? userId : "anonymous");
            log.setSessionId(sessionId != null ? sessionId : "unknown");
            log.setResultCount(resultCount);
            log.setTimeTookMs(timeTookMs);
            log.setTimestamp(Instant.now());

            // Build a safe summary of filters applied
            StringBuilder filters = new StringBuilder();
            if (originalQuery.getCategoryFilter() != null) filters.append("category:").append(originalQuery.getCategoryFilter()).append(";");
            if (originalQuery.getBrandFilter() != null) filters.append("brand:").append(originalQuery.getBrandFilter()).append(";");
            if (originalQuery.getMinPrice() != null) filters.append("minPrice:").append(originalQuery.getMinPrice()).append(";");
            if (originalQuery.getMaxPrice() != null) filters.append("maxPrice:").append(originalQuery.getMaxPrice()).append(";");
            log.setFilters(filters.toString());

            Map<String, Object> logMap = new HashMap<>();
            logMap.put("queryText", log.getQueryText());
            logMap.put("userId", log.getUserId());
            logMap.put("sessionId", log.getSessionId());
            logMap.put("resultCount", log.getResultCount());
            logMap.put("timeTookMs", log.getTimeTookMs());
            logMap.put("timestamp", log.getTimestamp().toString());
            logMap.put("filters", log.getFilters());

            IndexRequest request = new IndexRequest(ElasticsearchIndexService.SEARCH_QUERIES_INDEX)
                    .id(log.getId())
                    .source(logMap, XContentType.JSON);

            client.index(request, RequestOptions.DEFAULT);
        } catch (Exception e) {
            // Don't let logging failures affect search results
            logger.warn("Failed to log search query", e);
        }
    }
}

