package com.ecommerce.search.controller;

import com.ecommerce.search.model.Product;
import com.ecommerce.search.service.ProductIndexingService;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import javax.validation.Valid;
import java.io.IOException;
import java.util.List;
import java.util.Map;

@RestController
@RequestMapping("/api/products")
public class ProductController {

    private final ProductIndexingService indexingService;

    @Autowired
    public ProductController(ProductIndexingService indexingService) {
        this.indexingService = indexingService;
    }

    @PostMapping
    public ResponseEntity<Map<String, String>> indexProduct(@Valid @RequestBody Product product) throws IOException {
        String id = indexingService.indexProduct(product);
        return ResponseEntity.status(HttpStatus.CREATED)
                .body(Map.of("id", id, "message", "Product indexed successfully"));
    }

    @PostMapping("/bulk")
    public ResponseEntity<Map<String, String>> bulkIndex(@Valid @RequestBody List<Product> products) throws IOException {
        indexingService.bulkIndexProducts(products);
        return ResponseEntity.status(HttpStatus.CREATED)
                .body(Map.of("message", "Products indexed successfully", "count", String.valueOf(products.size())));
    }

    @GetMapping("/{id}")
    public ResponseEntity<Product> getProduct(@PathVariable String id) throws IOException {
        Product product = indexingService.getProduct(id);
        if (product == null) {
            return ResponseEntity.notFound().build();
        }
        return ResponseEntity.ok(product);
    }

    @PutMapping("/{id}")
    public ResponseEntity<Map<String, String>> updateProduct(@PathVariable String id,
                                                              @Valid @RequestBody Product product) throws IOException {
        String updatedId = indexingService.updateProduct(id, product);
        return ResponseEntity.ok(Map.of("id", updatedId, "message", "Product updated successfully"));
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<Map<String, String>> deleteProduct(@PathVariable String id) throws IOException {
        boolean deleted = indexingService.deleteProduct(id);
        if (deleted) {
            return ResponseEntity.ok(Map.of("message", "Product deleted successfully"));
        }
        return ResponseEntity.notFound().build();
    }
}

