package com.ecommerce.search.controller;

import com.ecommerce.search.model.SearchQuery;
import com.ecommerce.search.model.SearchResult;
import com.ecommerce.search.service.ProductSearchService;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.Authentication;
import org.springframework.web.bind.annotation.*;

import javax.validation.Valid;
import javax.validation.constraints.Size;
import java.io.IOException;
import java.util.List;
import java.util.Map;

@RestController
@RequestMapping("/api/search")
public class SearchController {

    private final ProductSearchService searchService;

    @Autowired
    public SearchController(ProductSearchService searchService) {
        this.searchService = searchService;
    }

    @PostMapping
    public ResponseEntity<SearchResult> search(@Valid @RequestBody SearchQuery query,
                                                Authentication authentication,
                                                @RequestHeader(value = "X-Session-Id", required = false)
                                                @Size(max = 64) String sessionId) throws IOException {
        String userId = authentication != null ? authentication.getName() : "anonymous";
        SearchResult result = searchService.search(query, userId, sessionId);
        return ResponseEntity.ok(result);
    }

    @GetMapping("/suggest")
    public ResponseEntity<Map<String, List<String>>> suggest(
            @RequestParam @Size(min = 2, max = 100) String prefix) throws IOException {
        List<String> suggestions = searchService.suggest(prefix);
        return ResponseEntity.ok(Map.of("suggestions", suggestions));
    }
}

